7428	int redisFork(int purpose) {
7429	    /* Guards against re-entrant RM_Fork from a FORK_CHILD_PRE event handler. */
7430	    static int fork_in_progress = 0;
7431	
7432	    if (fork_in_progress ||
7433	        (isMutuallyExclusiveChildType(purpose) && hasActiveChildProcess()))
7434	    {
7435	        errno = EEXIST;
7436	        return -1;
7437	    }
7438	    fork_in_progress = 1;
7439	
7440	    /* Let multi-threaded modules reach a fork-safe point: a background thread
7441	     * holding a lock (e.g. the allocator lock) at fork() time would deadlock the
7442	     * child. Handlers run synchronously and resume on FORK_CHILD_BORN/CANCELLED */
7443	    moduleFireServerEvent(REDISMODULE_EVENT_FORK_CHILD,
7444	                          REDISMODULE_SUBEVENT_FORK_CHILD_PRE,
7445	                          NULL);
7446	
7447	    if (isMutuallyExclusiveChildType(purpose))
7448	        openChildInfoPipe();
7449	
7450	    int childpid;
7451	    long long start = ustime();
7452	    if (server.debug_fork_fail) { /* used by tests */
7453	        errno = EAGAIN;
7454	        childpid = -1;
7455	    } else {
7456	        childpid = fork();
7457	    }
7458	    if (childpid == 0) {
7459	        /* Child.
7460	         *
7461	         * The order of setting things up follows some reasoning:
7462	         * Setup signal handlers first because a signal could fire at any time.
7463	         * Adjust OOM score before everything else to assist the OOM killer if
7464	         * memory resources are low.
7465	         */
7466	        server.in_fork_child = purpose;
7467	        setupChildSignalHandlers();
7468	        setOOMScoreAdj(CONFIG_OOM_BGCHILD);
7469	        updateDictResizePolicy();
7470	        dismissMemoryInChild();
7471	        closeChildUnusedResourceAfterFork();
7472	        /* Memory tracking for slots is unnecessary in child processes. */
7473	        server.memory_tracking_enabled = 0;
7474	        /* Close the reading part, so that if the parent crashes, the child will
7475	         * get a write error and exit. */
7476	        if (server.child_info_pipe[0] != -1)
7477	            close(server.child_info_pipe[0]);
7478	    } else {
7479	        /* Parent */
7480	        if (childpid == -1) {
7481	            int fork_errno = errno;
7482	            if (isMutuallyExclusiveChildType(purpose)) closeChildInfoPipe();
7483	            /* The fork we prepared for did not happen; let modules resume the
7484	             * background threads they quiesced on FORK_CHILD_PRE. */
7485	            moduleFireServerEvent(REDISMODULE_EVENT_FORK_CHILD,
7486	                                  REDISMODULE_SUBEVENT_FORK_CHILD_CANCELLED,
7487	                                  NULL);
7488	            fork_in_progress = 0;
7489	            errno = fork_errno;
7490	            return -1;
7491	        }
7492	
7493	        server.stat_total_forks++;
7494	        server.stat_fork_time = ustime()-start;
7495	        server.stat_fork_rate = (double) zmalloc_used_memory() * 1000000 / server.stat_fork_time / (1024*1024*1024); /* GB per second. */
7496	        latencyAddSampleIfNeeded("fork",server.stat_fork_time/1000);
